import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameState {
  MENU = 'MENU',
  LOADING = 'LOADING',
  PLAYING = 'PLAYING',
  GAMEOVER = 'GAMEOVER',
  MISSION_BRIEF = 'MISSION_BRIEF'
}

export interface Mission {
  title: string;
  objective: string;
  location: string;
  difficulty: 'Easy' | 'Medium' | 'Hard' | 'Extreme';
  threatLevel: number;
}

export interface PlayerStats {
  health: number;
  ammo: number;
  maxAmmo: number;
  score: number;
  kills: number;
}

export interface Enemy {
  id: string;
  position: [number, number, number];
  health: number;
  type: 'soldier' | 'drone' | 'tank';
  isAlive: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Mission } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateMission = async (): Promise<Mission> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Generate a realistic military FPS mission briefing in a near-future setting.",
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            objective: { type: Type.STRING },
            location: { type: Type.STRING },
            difficulty: { 
              type: Type.STRING,
              description: "One of: Easy, Medium, Hard, Extreme"
            },
            threatLevel: { type: Type.NUMBER }
          },
          required: ["title", "objective", "location", "difficulty", "threatLevel"]
        }
      }
    });

    return JSON.parse(response.text.trim()) as Mission;
  } catch (error) {
    console.error("Failed to generate mission:", error);
    return {
      title: "Operation: Dark Sky",
      objective: "Neutralize all hostiles in the urban sector.",
      location: "Neo-Tokyo Industrial Zone",
      difficulty: "Medium",
      threatLevel: 75
    };
  }
};

