import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const Weapon: React.FC<{ isFiring: boolean }> = ({ isFiring }) => {
  const groupRef = useRef<THREE.Group>(null);
  const muzzleFlashRef = useRef<THREE.PointLight>(null);

  useFrame((state) => {
    if (!groupRef.current) return;

    // Weapon sway
    const time = state.clock.getElapsedTime();
    const swayX = Math.sin(time * 2) * 0.005;
    const swayY = Math.cos(time * 3) * 0.005;

    groupRef.current.position.x = 0.5 + swayX;
    groupRef.current.position.y = -0.4 + swayY;
    groupRef.current.position.z = -0.8;

    // Recoil effect
    if (isFiring) {
        groupRef.current.position.z += 0.05;
        groupRef.current.rotation.x += 0.05;
    } else {
        groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, 0, 0.2);
    }
  });

  return (
    <group ref={groupRef}>
      {/* Main Body */}
      <mesh position={[0, 0, 0]}>
        <boxGeometry args={[0.15, 0.2, 1]} />
        <meshStandardMaterial color="#222" metalness={0.8} roughness={0.2} />
      </mesh>

      {/* Barrel */}
      <mesh position={[0, 0.05, -0.6]} rotation={[Math.PI / 2, 0, 0]}>
        <cylinderGeometry args={[0.04, 0.04, 0.8]} />
        <meshStandardMaterial color="#111" metalness={0.9} roughness={0.1} />
      </mesh>

      {/* Rail/Scope */}
      <mesh position={[0, 0.15, -0.2]}>
        <boxGeometry args={[0.08, 0.08, 0.4]} />
        <meshStandardMaterial color="#333" />
      </mesh>

      {/* Muzzle Flash Light */}
      <pointLight 
        ref={muzzleFlashRef}
        position={[0, 0.05, -1]} 
        intensity={isFiring ? 5 : 0} 
        color="#00ffff" 
        distance={5}
      />
    </group>
  );
};

export default Weapon;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { PointerLockControls, Sky, Stars, ContactShadows, Environment } from '@react-three/drei';
import * as THREE from 'three';
import Weapon from './Weapon';
import { Enemy } from '../types';

interface GameWorldProps {
  isPaused: boolean;
  onHit: () => void;
  onKill: () => void;
  onFire: () => void;
}

const EnemyNPC: React.FC<{ enemy: Enemy; onHit: (id: string) => void }> = ({ enemy, onHit }) => {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (!meshRef.current || !enemy.isAlive) return;
    // Simple logic: hover and pulse
    const t = state.clock.getElapsedTime();
    meshRef.current.position.y = enemy.position[1] + Math.sin(t * 2 + enemy.position[0]) * 0.2;
    meshRef.current.rotation.y += 0.01;
  });

  if (!enemy.isAlive) return null;

  return (
    <group position={enemy.position}>
        {/* Core */}
        <mesh ref={meshRef} onClick={() => onHit(enemy.id)}>
            <octahedronGeometry args={[0.8, 0]} />
            <meshStandardMaterial 
                color="#ff3333" 
                emissive="#ff0000" 
                emissiveIntensity={2} 
                wireframe
            />
        </mesh>
        {/* Outer Shield */}
        <mesh scale={[1.2, 1.2, 1.2]}>
             <sphereGeometry args={[1, 16, 16]} />
             <meshStandardMaterial 
                color="#ff0000" 
                transparent 
                opacity={0.1} 
                metalness={1} 
                roughness={0} 
             />
        </mesh>
        <pointLight intensity={1} color="#ff0000" distance={10} />
    </group>
  );
};

const ShootingManager: React.FC<{ onFire: () => void; onKill: () => void }> = ({ onFire, onKill }) => {
  const { camera, scene } = useThree();
  const [isFiring, setIsFiring] = useState(false);
  const raycaster = useRef(new THREE.Raycaster());

  const fire = useCallback(() => {
    onFire();
    setIsFiring(true);
    setTimeout(() => setIsFiring(false), 50);

    // Shooting logic
    raycaster.current.setFromCamera({ x: 0, y: 0 }, camera);
    const intersects = raycaster.current.intersectObjects(scene.children, true);

    // Check if we hit an enemy (represented by a specific user data or name)
    for (const intersect of intersects) {
        // In a real game, we'd check against a list of enemy meshes
        // Here, we simplify by checking if the object has been clicked via R3F events 
        // or just detecting "hit" on specific materials
    }
  }, [camera, scene, onFire]);

  useEffect(() => {
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 0) fire();
    };
    window.addEventListener('mousedown', handleMouseDown);
    return () => window.removeEventListener('mousedown', handleMouseDown);
  }, [fire]);

  return (
    <group>
        <Weapon isFiring={isFiring} />
    </group>
  );
};

const Scene: React.FC<GameWorldProps> = ({ isPaused, onHit, onKill, onFire }) => {
  const [enemies, setEnemies] = useState<Enemy[]>([
    { id: '1', position: [10, 2, -10], health: 100, type: 'soldier', isAlive: true },
    { id: '2', position: [-15, 2, -20], health: 100, type: 'soldier', isAlive: true },
    { id: '3', position: [5, 2, -30], health: 100, type: 'soldier', isAlive: true },
    { id: '4', position: [-5, 2, -15], health: 100, type: 'soldier', isAlive: true },
    { id: '5', position: [20, 2, -5], health: 100, type: 'soldier', isAlive: true },
  ]);

  const handleEnemyHit = (id: string) => {
    setEnemies(prev => prev.map(e => {
        if (e.id === id) {
            onKill(); // For simplicity, 1 hit = 1 kill in this demo
            return { ...e, isAlive: false };
        }
        return e;
    }));
  };

  return (
    <>
      <Sky sunPosition={[100, 20, 100]} />
      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />
      <ambientLight intensity={0.2} />
      <pointLight position={[10, 10, 10]} intensity={1.5} color="#44aaff" />
      <Environment preset="city" />

      {/* Grid Floor */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0, 0]}>
        <planeGeometry args={[1000, 1000]} />
        <meshStandardMaterial color="#0a0a0a" metalness={0.8} roughness={0.5} />
      </mesh>
      <gridHelper args={[1000, 100, '#222', '#111']} rotation={[0, 0, 0]} />

      {/* Atmospheric Objects */}
      <mesh position={[0, 50, -100]}>
        <sphereGeometry args={[20, 32, 32]} />
        <meshStandardMaterial color="#111" emissive="#00ffff" emissiveIntensity={0.1} />
      </mesh>

      {/* Enemies */}
      {enemies.map(enemy => (
        <EnemyNPC key={enemy.id} enemy={enemy} onHit={handleEnemyHit} />
      ))}

      {/* Player Setup */}
      {!isPaused && (
        <group>
          <ShootingManager onFire={onFire} onKill={onKill} />
          <PointerLockControls />
        </group>
      )}

      {/* Collision Boxes (Invisible for walls) */}
      <mesh position={[0, 5, -50]}>
        <boxGeometry args={[100, 10, 2]} />
        <meshStandardMaterial color="#111" />
      </mesh>
    </>
  );
};

const GameWorld: React.FC<GameWorldProps> = (props) => {
  return (
    <div className="w-full h-full cursor-crosshair">
      <Canvas shadows camera={{ fov: 75, position: [0, 1.8, 5] }}>
        <Scene {...props} />
      </Canvas>
    </div>
  );
};

export default GameWorld;

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, PlayerStats, Mission } from './types';
import { generateMission } from './services/geminiService';
import HUD from './components/HUD';
import GameWorld from './components/GameWorld';
import { Terminal, Shield, Play, RotateCcw, Award, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [mission, setMission] = useState<Mission | null>(null);
  const [stats, setStats] = useState<PlayerStats>({
    health: 100,
    ammo: 30,
    maxAmmo: 30,
    score: 0,
    kills: 0
  });

  const startNewGame = async () => {
    setGameState(GameState.LOADING);
    const newMission = await generateMission();
    setMission(newMission);
    setStats({
      health: 100,
      ammo: 30,
      maxAmmo: 30,
      score: 0,
      kills: 0
    });
    setGameState(GameState.MISSION_BRIEF);
  };

  const handleFire = useCallback(() => {
    setStats(prev => {
        if (prev.ammo <= 0) return prev;
        return { ...prev, ammo: prev.ammo - 1 };
    });
  }, []);

  const handleKill = useCallback(() => {
    setStats(prev => ({
        ...prev,
        score: prev.score + 500,
        kills: prev.kills + 1
    }));
  }, []);

  const handleHit = useCallback(() => {
    setStats(prev => {
        const newHealth = Math.max(0, prev.health - 10);
        if (newHealth === 0) setGameState(GameState.GAMEOVER);
        return { ...prev, health: newHealth };
    });
  }, []);

  // Reload mechanic (automated for demo simplicity)
  useEffect(() => {
    if (stats.ammo === 0) {
        const timer = setTimeout(() => {
            setStats(prev => ({ ...prev, ammo: prev.maxAmmo }));
        }, 1500);
        return () => clearTimeout(timer);
    }
  }, [stats.ammo]);

  return (
    <div className="w-full h-screen bg-neutral-950 text-white overflow-hidden select-none">
      {/* Menu State */}
      {gameState === GameState.MENU && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-900 to-black p-6">
          <div className="mb-8 flex flex-col items-center">
            <div className="flex items-center gap-3 text-cyan-400 mb-2">
                <Shield className="w-8 h-8" />
                <span className="text-sm tracking-[0.5em] font-light uppercase">United Galactic Alliance</span>
            </div>
            <h1 className="text-7xl md:text-9xl font-black italic tracking-tighter text-white drop-shadow-2xl">
              GEMINI<span className="text-cyan-500">STRIKE</span>
            </h1>
          </div>

          <div className="max-w-md w-full space-y-4">
            <button 
              onClick={startNewGame}
              className="w-full bg-cyan-600 hover:bg-cyan-500 text-black font-bold py-4 rounded-sm flex items-center justify-center gap-2 transition-all transform hover:scale-105 active:scale-95"
            >
              <Play className="w-5 h-5 fill-current" />
              INITIATE NEURAL LINK
            </button>
            <div className="grid grid-cols-2 gap-4">
                <button className="bg-white/5 hover:bg-white/10 border border-white/10 py-3 text-xs tracking-widest uppercase rounded-sm">Training Room</button>
                <button className="bg-white/5 hover:bg-white/10 border border-white/10 py-3 text-xs tracking-widest uppercase rounded-sm">Armory</button>
            </div>
          </div>

          <div className="absolute bottom-8 text-[10px] text-white/30 tracking-[0.3em] uppercase">
            Protocol v2.5.0 // Secure Connection: Active
          </div>
        </div>
      )}

      {/* Loading State */}
      {gameState === GameState.LOADING && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-black">
          <Terminal className="w-12 h-12 text-cyan-500 animate-pulse mb-4" />
          <div className="text-xl font-mono text-cyan-500 tracking-widest">CONNECTING TO GEMINI TACTICAL NETWORK...</div>
          <div className="mt-8 w-64 h-1 bg-white/10 rounded-full overflow-hidden">
            <div className="h-full bg-cyan-500 animate-[loading_2s_ease-in-out_infinite]"></div>
          </div>
          <style>{`
            @keyframes loading {
              0% { width: 0%; transform: translateX(-100%); }
              100% { width: 100%; transform: translateX(100%); }
            }
          `}</style>
        </div>
      )}

      {/* Mission Briefing State */}
      {gameState === GameState.MISSION_BRIEF && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-xl p-8">
          <div className="max-w-3xl w-full border border-cyan-500/30 p-12 bg-slate-900/40 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4">
                <AlertTriangle className="text-amber-500 w-12 h-12 opacity-20" />
            </div>

            <div className="flex items-center gap-4 mb-8">
                <div className="w-2 h-12 bg-cyan-500"></div>
                <div>
                    <div className="text-xs uppercase tracking-[0.3em] text-cyan-500/70 font-bold mb-1">Combat Intelligence Report</div>
                    <h2 className="text-4xl font-black tracking-tight">{mission?.title}</h2>
                </div>
            </div>

            <div className="grid md:grid-cols-2 gap-12 mb-12">
                <div className="space-y-6">
                    <div>
                        <div className="text-[10px] uppercase tracking-widest text-white/40 mb-2">Deployment Zone</div>
                        <div className="text-lg font-mono">{mission?.location}</div>
                    </div>
                    <div>
                        <div className="text-[10px] uppercase tracking-widest text-white/40 mb-2">Threat Assessment</div>
                        <div className="flex items-center gap-2">
                            <span className="px-3 py-1 bg-red-900/30 border border-red-500/50 text-red-400 text-xs font-bold rounded-sm">
                                {mission?.difficulty.toUpperCase()}
                            </span>
                            <div className="text-sm font-mono text-white/70">LVL {mission?.threatLevel}</div>
                        </div>
                    </div>
                </div>
                <div>
                    <div className="text-[10px] uppercase tracking-widest text-white/40 mb-2">Mission Objectives</div>
                    <p className="text-white/80 leading-relaxed italic text-lg">"{mission?.objective}"</p>
                </div>
            </div>

            <button 
              onClick={() => setGameState(GameState.PLAYING)}
              className="group relative w-full overflow-hidden bg-white text-black font-black py-4 tracking-widest hover:bg-cyan-500 transition-colors"
            >
              <div className="relative z-10 flex items-center justify-center gap-2">
                CONFIRM DEPLOYMENT
              </div>
            </button>
          </div>
        </div>
      )}

      {/* Playing State */}
      {gameState === GameState.PLAYING && (
        <>
            <GameWorld 
                isPaused={false} 
                onHit={handleHit} 
                onKill={handleKill} 
                onFire={handleFire}
            />
            <HUD stats={stats} mission={mission} />

            <div className="fixed top-8 left-1/2 -translate-x-1/2 text-[10px] text-white/20 uppercase tracking-[0.5em] pointer-events-none">
                WASD TO MOVE // MOUSE TO AIM // LEFT CLICK TO FIRE
            </div>
        </>
      )}

      {/* Game Over State */}
      {gameState === GameState.GAMEOVER && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-red-950/90 backdrop-blur-3xl p-6">
          <AlertTriangle className="w-24 h-24 text-white mb-6 animate-bounce" />
          <h2 className="text-7xl font-black italic tracking-tighter mb-2">TACTICAL FAILURE</h2>
          <p className="text-white/60 mb-12 tracking-widest">NEURAL LINK SEVERED // UNIT DECOMMISSIONED</p>

          <div className="flex gap-4 mb-12">
            <div className="bg-black/50 p-6 rounded text-center min-w-[150px] border border-white/5">
                <Award className="w-6 h-6 mx-auto mb-2 text-amber-500" />
                <div className="text-xs text-white/40 uppercase mb-1">Final Score</div>
                <div className="text-3xl font-black">{stats.score}</div>
            </div>
            <div className="bg-black/50 p-6 rounded text-center min-w-[150px] border border-white/5">
                <Target className="w-6 h-6 mx-auto mb-2 text-cyan-400" />
                <div className="text-xs text-white/40 uppercase mb-1">Eliminations</div>
                <div className="text-3xl font-black">{stats.kills}</div>
            </div>
          </div>

          <button 
            onClick={startNewGame}
            className="bg-white text-black font-black px-12 py-4 tracking-widest flex items-center gap-2 hover:bg-cyan-400 transition-all"
          >
            <RotateCcw className="w-5 h-5" />
            RE-DEPLOY UNIT
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

