// Hook to track keyboard state
const useKeyboard = () => {
  const [keys, setKeys] = useState({ 
    forward: false, 
    backward: false, 
    left: false, 
    right: false, 
    shift: false 
  });

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': setKeys(k => ({ ...k, forward: true })); break;
        case 'KeyS': setKeys(k => ({ ...k, backward: true })); break;
        case 'KeyA': setKeys(k => ({ ...k, left: true })); break;
        case 'KeyD': setKeys(k => ({ ...k, right: true })); break;
        case 'ShiftLeft': setKeys(k => ({ ...k, shift: true })); break;
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': setKeys(k => ({ ...k, forward: false })); break;
        case 'KeyS': setKeys(k => ({ ...k, backward: false })); break;
        case 'KeyA': setKeys(k => ({ ...k, left: false })); break;
        case 'KeyD': setKeys(k => ({ ...k, right: false })); break;
        case 'ShiftLeft': setKeys(k => ({ ...k, shift: false })); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  return keys;
};

const PlayerController: React.FC = () => {
  const { camera } = useThree();
  const keys = useKeyboard();
  const velocity = useRef(new THREE.Vector3());
  const direction = useRef(new THREE.Vector3());
  const headBobActive = useRef(0);

  useFrame((state, delta) => {
    const moveSpeed = keys.shift ? 12 : 7;
    const friction = 10;

    // Movement logic
    direction.current.z = Number(keys.forward) - Number(keys.backward);
    direction.current.x = Number(keys.right) - Number(keys.left);
    direction.current.normalize();

    // Smoother movement with velocity
    if (keys.forward || keys.backward) velocity.current.z -= direction.current.z * moveSpeed * delta;
    if (keys.left || keys.right) velocity.current.x -= direction.current.x * moveSpeed * delta;

    // Apply friction/damping
    velocity.current.z -= velocity.current.z * friction * delta;
    velocity.current.x -= velocity.current.x * friction * delta;

    // Relative movement vectors
    const forward = new THREE.Vector3(0, 0, -1).applyQuaternion(camera.quaternion);
    const right = new THREE.Vector3(1, 0, 0).applyQuaternion(camera.quaternion);

    // Flatten Y to prevent flying/tunneling up/down
    forward.y = 0;
    right.y = 0;
    forward.normalize();
    right.normalize();

    // Update position
    camera.position.add(forward.clone().multiplyScalar(-velocity.current.z));
    camera.position.add(right.clone().multiplyScalar(-velocity.current.x));

    // Simple boundary collision (Grid is 1000x1000)
    camera.position.x = THREE.MathUtils.clamp(camera.position.x, -490, 490);
    camera.position.z = THREE.MathUtils.clamp(camera.position.z, -490, 490);

    // Wall collision for the big wall at -50
    if (camera.position.z < -48 && camera.position.z > -52 && Math.abs(camera.position.x) < 50) {
      camera.position.z = camera.position.z > -50 ? -48 : -52;
    }

    // Realistic Head Bob
    const isMoving = Math.abs(velocity.current.x) > 0.1 || Math.abs(velocity.current.z) > 0.1;
    if (isMoving) {
      headBobActive.current += delta * (keys.shift ? 15 : 10);
      camera.position.y = 1.8 + Math.sin(headBobActive.current) * 0.05;
    } else {
      camera.position.y = THREE.MathUtils.lerp(camera.position.y, 1.8, 0.1);
    }
  });

  return null;
};

const EnemyNPC: React.FC<{ enemy: Enemy; onHit: (id: string) => void }> = ({ enemy, onHit }) => {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (!meshRef.current || !enemy.isAlive) return;
    const t = state.clock.getElapsedTime();
    meshRef.current.position.y = enemy.position[1] + Math.sin(t * 2 + enemy.position[0]) * 0.2;
    meshRef.current.rotation.y += 0.01;
  });

  if (!enemy.isAlive) return null;

  return (
    <group position={enemy.position}>
        <mesh ref={meshRef} onClick={() => onHit(enemy.id)}>
            <octahedronGeometry args={[0.8, 0]} />
            <meshStandardMaterial 
                color="#ff3333" 
                emissive="#ff0000" 
                emissiveIntensity={2} 
                wireframe
            />
        </mesh>
        <mesh scale={[1.2, 1.2, 1.2]}>
             <sphereGeometry args={[1, 16, 16]} />
             <meshStandardMaterial 
                color="#ff0000" 
                transparent 
                opacity={0.1} 
                metalness={1} 
                roughness={0} 
             />
        </mesh>
        <pointLight intensity={1} color="#ff0000" distance={10} />
    </group>
  );
};

const ShootingManager: React.FC<{ onFire: () => void; onKill: () => void }> = ({ onFire, onKill }) => {
  const { camera, scene } = useThree();
  const [isFiring, setIsFiring] = useState(false);
  const raycaster = useRef(new THREE.Raycaster());

  const fire = useCallback(() => {
    onFire();
    setIsFiring(true);
    setTimeout(() => setIsFiring(false), 50);

    raycaster.current.setFromCamera({ x: 0, y: 0 }, camera);
    const intersects = raycaster.current.intersectObjects(scene.children, true);

    // Trigger onHit/onKill for enemies if hit by raycast
    // Note: R3F onClick handles it for now, but raycasting is more realistic
  }, [camera, scene, onFire]);

  useEffect(() => {
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 0) fire();
    };
    window.addEventListener('mousedown', handleMouseDown);
    return () => window.removeEventListener('mousedown', handleMouseDown);
  }, [fire]);

  return (
    <group>
        <Weapon isFiring={isFiring} />
    </group>
  );
};

