  const headBobActive = useRef(0);

  useFrame((state, delta) => {
    const moveSpeed = keys.shift ? 14 : 8;
    const friction = 10;

    direction.current.z = Number(keys.forward) - Number(keys.backward);
    direction.current.x = Number(keys.right) - Number(keys.left);
    direction.current.normalize();

    if (keys.forward || keys.backward) velocity.current.z -= direction.current.z * moveSpeed * delta;
