    return list;
  }, []);

  const [enemies, setEnemies] = useState<Enemy[]>(initialEnemies);

  const handleEnemyHit = (id: string) => {
    setEnemies(prev => prev.map(e => {
        if (e.id === id) {
            onKill();
            return { ...e, isAlive: false };
        }
        return e;
    }));
  };

  return (
    <>
      <Sky sunPosition={[100, 20, 100]} />
      <Stars radius={150} depth={50} count={7000} factor={4} saturation={0} fade speed={1} />
      <ambientLight intensity={0.1} />
      <pointLight position={[0, 15, 0]} intensity={2} color="#00ffff" />
      <Environment preset="city" />

      {/* Grid Floor */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0, 0]} receiveShadow>
        <planeGeometry args={[1000, 1000]} />
        <meshStandardMaterial color="#050505" metalness={0.9} roughness={0.3} />
      </mesh>
      <gridHelper args={[1000, 100, '#111', '#050505']} position={[0, 0.01, 0]} />

      <TacticalMap />

      {enemies.map(enemy => (
        <EnemyNPC key={enemy.id} enemy={enemy} onHit={handleEnemyHit} onPlayerHurt={onHit} />
      ))}

      {!isPaused && (
        <group>
          <PlayerController />
          <ShootingManager onFire={onFire} />
          <PointerLockControls />
        </group>
      )}
    </>
  );
};

