const PlayerController: React.FC<{ extractionReady: boolean; onVictory: () => void }> = ({ extractionReady, onVictory }) => {
  const { camera } = useThree();
  const keys = useKeyboard();
  const velocity = useRef(new THREE.Vector3());
  const direction = useRef(new THREE.Vector3());
  const verticalVelocity = useRef(0);
  const headBobActive = useRef(0);
  const isGrounded = useRef(true);

  const GRAVITY = -30;
  const JUMP_FORCE = 12;
  const GROUND_Y = 1.8;

  useFrame((state, delta) => {
    const moveSpeed = keys.shift ? 14 : 8;
    const friction = 10;

    direction.current.z = Number(keys.forward) - Number(keys.backward);
    direction.current.x = Number(keys.right) - Number(keys.left);
    direction.current.normalize();

    if (keys.forward || keys.backward) velocity.current.z -= direction.current.z * moveSpeed * delta;
    if (keys.left || keys.right) velocity.current.x -= direction.current.x * moveSpeed * delta;

    velocity.current.z -= velocity.current.z * friction * delta;
    velocity.current.x -= velocity.current.x * friction * delta;

    const forward = new THREE.Vector3(0, 0, -1).applyQuaternion(camera.quaternion);
    const right = new THREE.Vector3(1, 0, 0).applyQuaternion(camera.quaternion);

    forward.y = 0;
    right.y = 0;
    forward.normalize();
    right.normalize();

    camera.position.add(forward.clone().multiplyScalar(-velocity.current.z));
    camera.position.add(right.clone().multiplyScalar(-velocity.current.x));

    // Jump and Gravity logic
    if (keys.jump && isGrounded.current) {
      verticalVelocity.current = JUMP_FORCE;
      isGrounded.current = false;
    }

    if (!isGrounded.current) {
      verticalVelocity.current += GRAVITY * delta;
      camera.position.y += verticalVelocity.current * delta;

      if (camera.position.y <= GROUND_Y) {
        camera.position.y = GROUND_Y;
        verticalVelocity.current = 0;
        isGrounded.current = true;
      }
    }

    // Hard Boundaries
    camera.position.x = THREE.MathUtils.clamp(camera.position.x, -95, 95);
    camera.position.z = THREE.MathUtils.clamp(camera.position.z, -95, 95);

    // Extraction Detection
    if (extractionReady) {
      const distToCenter = new THREE.Vector2(camera.position.x, camera.position.z).length();
      if (distToCenter < 5) {
        onVictory();
      }
    }

    // Realistic Head Bob (only if on ground)
    const isMoving = Math.abs(velocity.current.x) > 0.1 || Math.abs(velocity.current.z) > 0.1;
    if (isMoving && isGrounded.current) {
      headBobActive.current += delta * (keys.shift ? 15 : 10);
      camera.position.y = GROUND_Y + Math.sin(headBobActive.current) * 0.05;
    } else if (isGrounded.current) {
      camera.position.y = THREE.MathUtils.lerp(camera.position.y, GROUND_Y, 0.1);
    }
  });

  return null;
};

const EnemyNPC: React.FC<{ enemy: Enemy; onHit: (id: string) => void; onPlayerHurt: () => void }> = ({ enemy, onHit, onPlayerHurt }) => {
  const meshRef = useRef<THREE.Mesh>(null);
  const glowRef = useRef<THREE.PointLight>(null);
  const { camera } = useThree();
  const lastFireTime = useRef(0);

  useFrame((state) => {
    if (!meshRef.current || !enemy.isAlive) return;
    const t = state.clock.getElapsedTime();

    // Animation
    meshRef.current.position.y = enemy.position[1] + Math.sin(t * 2 + enemy.position[0]) * 0.2;
    meshRef.current.rotation.y += 0.01;
    meshRef.current.lookAt(camera.position.x, enemy.position[1], camera.position.z);

    // Hostile Behavior: Fire if close enough and every ~3-5 seconds
    const dist = camera.position.distanceTo(new THREE.Vector3(...enemy.position));
    if (dist < 40 && t - lastFireTime.current > (3 + Math.random() * 2)) {
      lastFireTime.current = t;
      if (Math.random() > 0.6) {
        onPlayerHurt();
      }
      if (glowRef.current) {
        glowRef.current.intensity = 5;
        setTimeout(() => { if (glowRef.current) glowRef.current.intensity = 1; }, 100);
      }
    }
  });

  if (!enemy.isAlive) return null;

  return (
    <group position={enemy.position}>
        <mesh 
          ref={meshRef} 
          onClick={(e) => {
            e.stopPropagation();
            onHit(enemy.id);
          }}
        >
            <octahedronGeometry args={[enemy.type === 'tank' ? 1.5 : 0.8, 0]} />
            <meshStandardMaterial 
                color={enemy.type === 'tank' ? "#ffaa00" : "#ff3333"} 
                emissive={enemy.type === 'tank' ? "#ffaa00" : "#ff0000"} 
                emissiveIntensity={2} 
                wireframe
            />
        </mesh>
        <mesh scale={[1.2, 1.2, 1.2]}>
             <sphereGeometry args={[enemy.type === 'tank' ? 1.8 : 1, 16, 16]} />
             <meshStandardMaterial 
                color="#ff0000" 
                transparent 
                opacity={0.05} 
                metalness={1} 
                roughness={0} 
             />
        </mesh>
        <pointLight ref={glowRef} intensity={1} color="#ff0000" distance={15} />
    </group>
  );
};

const ShootingManager: React.FC<{ onFire: () => void }> = ({ onFire }) => {
  const [isFiring, setIsFiring] = useState(false);

  const fire = useCallback(() => {
    onFire();
    setIsFiring(true);
    setTimeout(() => setIsFiring(false), 50);
  }, [onFire]);

  useEffect(() => {
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 0) fire();
    };
    window.addEventListener('mousedown', handleMouseDown);
    return () => window.removeEventListener('mousedown', handleMouseDown);
  }, [fire]);

  return (
    <group>
        <Weapon isFiring={isFiring} />
    </group>
  );
};

const Scene: React.FC<GameWorldProps> = ({ isPaused, onHit, onKill, onFire, onVictory, enemiesRemaining }) => {
  const initialEnemies: Enemy[] = useMemo(() => {
    const list: Enemy[] = [];
    for (let i = 0; i < 18; i++) {
      const angle = (i / 18) * Math.PI * 2;
      const radius = 30 + Math.random() * 50;
      list.push({
        id: `e-${i}`,
        position: [
          Math.cos(angle) * radius,
          2,
          Math.sin(angle) * radius
        ],
        health: 100,
        type: i % 5 === 0 ? 'tank' : 'soldier',
        isAlive: true
      });
    }
    return list;
  }, []);

  const [enemies, setEnemies] = useState<Enemy[]>(initialEnemies);
  const extractionReady = enemiesRemaining <= 0;

  const handleEnemyHit = (id: string) => {
    setEnemies(prev => prev.map(e => {
        if (e.id === id) {
            onKill();
            return { ...e, isAlive: false };
        }
        return e;
    }));
  };

  return (
    <>
      <Sky sunPosition={[100, 20, 100]} />
      <Stars radius={150} depth={50} count={7000} factor={4} saturation={0} fade speed={1} />
      <ambientLight intensity={0.1} />
      <pointLight position={[0, 15, 0]} intensity={2} color="#00ffff" />
      <Environment preset="city" />

      {/* Grid Floor */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0, 0]} receiveShadow>
        <planeGeometry args={[1000, 1000]} />
        <meshStandardMaterial color="#050505" metalness={0.9} roughness={0.3} />
      </mesh>
      <gridHelper args={[1000, 100, '#111', '#050505']} position={[0, 0.01, 0]} />

      <TacticalMap extractionReady={extractionReady} />

      {enemies.map(enemy => (
        <EnemyNPC key={enemy.id} enemy={enemy} onHit={handleEnemyHit} onPlayerHurt={onHit} />
      ))}

      {!isPaused && (
        <group>
          <PlayerController extractionReady={extractionReady} onVictory={onVictory} />
          <ShootingManager onFire={onFire} />
          <PointerLockControls />
        </group>
      )}
    </>
  );
};

const GameWorld: React.FC<GameWorldProps> = (props) => {
  return (
    <div className="w-full h-full cursor-crosshair">
      <Canvas shadows camera={{ fov: 75, position: [0, 1.8, 10] }}>
        <Scene {...props} />
      </Canvas>
    </div>
  );
};

