import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const Weapon: React.FC<{ isFiring: boolean }> = ({ isFiring }) => {
  const groupRef = useRef<THREE.Group>(null);
  const muzzleFlashRef = useRef<THREE.Group>(null);
  const shellRef = useRef<THREE.Mesh>(null);
  const [lastFire, setLastFire] = useState(0);

  useFrame((state) => {
    if (!groupRef.current) return;

    const time = state.clock.getElapsedTime();

    // Weapon sway
    const swayX = Math.sin(time * 1.5) * 0.005;
    const swayY = Math.cos(time * 2) * 0.005;

    groupRef.current.position.x = 0.5 + swayX;
    groupRef.current.position.y = -0.4 + swayY;
    groupRef.current.position.z = -0.8;

    // Recoil and Muzzle Flash
    if (isFiring) {
        groupRef.current.position.z += 0.08;
        groupRef.current.rotation.x += 0.06;
        if (muzzleFlashRef.current) {
            muzzleFlashRef.current.visible = true;
            muzzleFlashRef.current.scale.setScalar(1 + Math.random() * 0.5);
            muzzleFlashRef.current.rotation.z = Math.random() * Math.PI;
        }
    } else {
        groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, 0, 0.15);
        if (muzzleFlashRef.current) muzzleFlashRef.current.visible = false;
    }

    // Shell ejection logic
    if (shellRef.current && isFiring) {
        shellRef.current.visible = true;
        shellRef.current.position.set(0.1, 0.05, -0.2);
    }
    if (shellRef.current && shellRef.current.visible) {
        shellRef.current.position.x += 0.1;
        shellRef.current.position.y += 0.05;
        shellRef.current.rotation.x += 0.5;
        if (shellRef.current.position.x > 1) shellRef.current.visible = false;
    }
  });

  return (
    <group ref={groupRef}>
      {/* Main Body */}
      <mesh position={[0, 0, 0]}>
        <boxGeometry args={[0.15, 0.2, 1]} />
        <meshStandardMaterial color="#1a1a1a" metalness={0.9} roughness={0.1} />
      </mesh>

      {/* Barrel */}
      <mesh position={[0, 0.05, -0.6]} rotation={[Math.PI / 2, 0, 0]}>
        <cylinderGeometry args={[0.04, 0.04, 0.8]} />
        <meshStandardMaterial color="#050505" metalness={1} roughness={0} />
      </mesh>

      {/* Shell Ejection Port */}
      <mesh ref={shellRef} visible={false}>
        <cylinderGeometry args={[0.01, 0.01, 0.04]} />
        <meshStandardMaterial color="#d4af37" metalness={1} />
      </mesh>

      {/* Volumetric Muzzle Flash */}
      <group ref={muzzleFlashRef} position={[0, 0.05, -1.1]} visible={false}>
        <mesh rotation={[0, 0, 0]}>
            <sphereGeometry args={[0.15, 8, 8]} />
            <meshBasicMaterial color="#00ffff" transparent opacity={0.8} />
        </mesh>
        <mesh rotation={[0, 0, Math.PI / 4]}>
            <boxGeometry args={[0.4, 0.02, 0.02]} />
            <meshBasicMaterial color="#ffffff" />
        </mesh>
        <mesh rotation={[0, 0, -Math.PI / 4]}>
            <boxGeometry args={[0.4, 0.02, 0.02]} />
            <meshBasicMaterial color="#ffffff" />
        </mesh>
        <pointLight intensity={10} color="#00ffff" distance={6} />
      </group>
    </group>
  );
};

