const EnemyNPC: React.FC<{ enemy: Enemy; onHit: (id: string, pos: THREE.Vector3) => void; onPlayerHurt: () => void }> = ({ enemy, onHit, onPlayerHurt }) => {
  const groupRef = useRef<THREE.Group>(null);
  const bodyRef = useRef<THREE.Group>(null);
  const leftLegRef = useRef<THREE.Mesh>(null);
  const rightLegRef = useRef<THREE.Mesh>(null);
  const leftArmRef = useRef<THREE.Mesh>(null);
  const rightArmRef = useRef<THREE.Mesh>(null);
  const { camera } = useThree();
  const lastFireTime = useRef(0);

  useFrame((state) => {
    if (!groupRef.current || !enemy.isAlive) return;
    const t = state.clock.getElapsedTime();

    // Look at player
    groupRef.current.lookAt(camera.position.x, enemy.position[1], camera.position.z);

    // Subtle breathing/idle animation
    if (bodyRef.current) {
      bodyRef.current.position.y = Math.sin(t * 1.5) * 0.05;
    }

    // Walking animation (if we were to add movement, but currently stationary/look-at)
    // Even while idle, we can have a slight shifting animation
    const swingSpeed = 2;
    const swingAmount = 0.2;
    if (leftLegRef.current && rightLegRef.current) {
        leftLegRef.current.rotation.x = Math.sin(t * swingSpeed) * swingAmount;
        rightLegRef.current.rotation.x = -Math.sin(t * swingSpeed) * swingAmount;
    }
    if (leftArmRef.current && rightArmRef.current) {
        leftArmRef.current.rotation.x = -Math.sin(t * swingSpeed) * swingAmount;
        rightArmRef.current.rotation.x = Math.sin(t * swingSpeed) * swingAmount;
    }

    // Firing logic
    if (camera.position.distanceTo(new THREE.Vector3(...enemy.position)) < 50 && t - lastFireTime.current > (2 + Math.random() * 3)) {
      lastFireTime.current = t;
      if (Math.random() > 0.7) onPlayerHurt();
    }
  });

  if (!enemy.isAlive) return null;

  const armorColor = enemy.type === 'tank' ? '#333' : '#1a1a1a';
  const detailColor = enemy.type === 'tank' ? '#ffaa00' : '#ff3333';
  const scale = enemy.type === 'tank' ? 1.3 : 1.0;

  return (
    <group ref={groupRef} position={enemy.position} scale={[scale, scale, scale]}>
      <group ref={bodyRef} onClick={(e) => { e.stopPropagation(); onHit(enemy.id, e.point); }}>
        {/* Torso */}
        <mesh position={[0, 1.2, 0]}>
          <boxGeometry args={[0.6, 0.8, 0.3]} />
          <meshStandardMaterial color={armorColor} metalness={0.7} roughness={0.2} />
        </mesh>

        {/* Head */}
        <group position={[0, 1.8, 0]}>
          <mesh>
            <boxGeometry args={[0.3, 0.35, 0.3]} />
            <meshStandardMaterial color="#0a0a0a" />
          </mesh>
          {/* Glowing Visor */}
          <mesh position={[0, 0.05, 0.16]}>
            <boxGeometry args={[0.25, 0.05, 0.02]} />
            <meshStandardMaterial color={detailColor} emissive={detailColor} emissiveIntensity={4} />
          </mesh>
        </group>

        {/* Arms */}
        <mesh ref={leftArmRef} position={[-0.45, 1.4, 0]}>
          <boxGeometry args={[0.2, 0.6, 0.2]} />
          <meshStandardMaterial color={armorColor} />
        </mesh>
        <mesh ref={rightArmRef} position={[0.45, 1.4, 0]}>
          <boxGeometry args={[0.2, 0.6, 0.2]} />
          <meshStandardMaterial color={armorColor} />
        </mesh>

        {/* Tactical Weapon (Simple block) */}
        <mesh position={[0.3, 1.1, 0.4]}>
          <boxGeometry args={[0.1, 0.1, 0.6]} />
          <meshStandardMaterial color="#000" />
        </mesh>

        {/* Legs */}
        <mesh ref={leftLegRef} position={[-0.2, 0.4, 0]}>
          <boxGeometry args={[0.22, 0.8, 0.22]} />
          <meshStandardMaterial color="#111" />
        </mesh>
        <mesh ref={rightLegRef} position={[0.2, 0.4, 0]}>
          <boxGeometry args={[0.22, 0.8, 0.22]} />
          <meshStandardMaterial color="#111" />
        </mesh>
      </group>
      {/* Light glow around enemy */}
      <pointLight position={[0, 1.5, 0]} intensity={0.5} color={detailColor} distance={5} />
    </group>
  );
};

