import * as THREE from 'three';
import Weapon from './Weapon';
import { Enemy, WeaponType, WEAPONS } from '../types';

interface GameWorldProps {
  isPaused: boolean;
  onHit: () => void;
  onKill: () => void;
  onFire: () => void;
  onVictory: () => void;
  enemiesRemaining: number;
  currentWeaponType: WeaponType;
}

// Particle system for impacts and explosions
const VFXManager = React.forwardRef((_, ref) => {
  const pointsRef = useRef<THREE.Points>(null);
  const particleCount = 2000;

  const particles = useMemo(() => {
    const pos = new Float32Array(particleCount * 3);
    const colors = new Float32Array(particleCount * 3);
    const velocities = new Float32Array(particleCount * 3);
    const lives = new Float32Array(particleCount);
    return { pos, colors, velocities, lives };
  }, []);

  const triggerEffect = useCallback((position: THREE.Vector3, color: THREE.Color, count: number = 20, speed: number = 0.2) => {
    let triggered = 0;
    for (let i = 0; i < particleCount && triggered < count; i++) {
        if (particles.lives[i] <= 0) {
            particles.pos[i * 3] = position.x;
            particles.pos[i * 3 + 1] = position.y;
            particles.pos[i * 3 + 2] = position.z;
            particles.velocities[i * 3] = (Math.random() - 0.5) * speed;
            particles.velocities[i * 3 + 1] = (Math.random() - 0.5) * speed + (speed * 0.5);
            particles.velocities[i * 3 + 2] = (Math.random() - 0.5) * speed;
            particles.colors[i * 3] = color.r;
            particles.colors[i * 3 + 1] = color.g;
            particles.colors[i * 3 + 2] = color.b;
            particles.lives[i] = 1.0;
            triggered++;
        }
    }
  }, [particles]);

  React.useImperativeHandle(ref, () => ({ triggerEffect }));

  useFrame((_, delta) => {
    if (!pointsRef.current) return;
    const positions = pointsRef.current.geometry.attributes.position;
    const colors = pointsRef.current.geometry.attributes.color;

    for (let i = 0; i < particleCount; i++) {
        if (particles.lives[i] > 0) {
            particles.lives[i] -= delta * 2;
            particles.pos[i * 3] += particles.velocities[i * 3];
            particles.pos[i * 3 + 1] += particles.velocities[i * 3 + 1];
            particles.pos[i * 3 + 2] += particles.velocities[i * 3 + 2];
            particles.velocities[i * 3 + 1] -= 0.01; // Gravity
            positions.setXYZ(i, particles.pos[i * 3], particles.pos[i * 3 + 1], particles.pos[i * 3 + 2]);
            const alpha = Math.max(0, particles.lives[i]);
            colors.setXYZ(i, particles.colors[i * 3] * alpha, particles.colors[i * 3 + 1] * alpha, particles.colors[i * 3 + 2] * alpha);
        } else {
            positions.setXYZ(i, 0, -100, 0);
        }
    }
    positions.needsUpdate = true;
    colors.needsUpdate = true;
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" count={particleCount} array={particles.pos} itemSize={3} />
        <bufferAttribute attach="attributes-color" count={particleCount} array={particles.colors} itemSize={3} />
      </bufferGeometry>
      <pointsMaterial size={0.1} vertexColors transparent blending={THREE.AdditiveBlending} />
    </points>
  );
});

const useKeyboard = () => {
  const [keys, setKeys] = useState({ forward: false, backward: false, left: false, right: false, shift: false, jump: false });
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': setKeys(k => ({ ...k, forward: true })); break;
        case 'KeyS': setKeys(k => ({ ...k, backward: true })); break;
        case 'KeyA': setKeys(k => ({ ...k, left: true })); break;
        case 'KeyD': setKeys(k => ({ ...k, right: true })); break;
        case 'ShiftLeft': setKeys(k => ({ ...k, shift: true })); break;
        case 'Space': setKeys(k => ({ ...k, jump: true })); break;
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': setKeys(k => ({ ...k, forward: false })); break;
        case 'KeyS': setKeys(k => ({ ...k, backward: false })); break;
        case 'KeyA': setKeys(k => ({ ...k, left: false })); break;
        case 'KeyD': setKeys(k => ({ ...k, right: false })); break;
        case 'ShiftLeft': setKeys(k => ({ ...k, shift: false })); break;
        case 'Space': setKeys(k => ({ ...k, jump: false })); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);
  return keys;
};

const TacticalMap: React.FC<{ extractionReady: boolean }> = ({ extractionReady }) => {
  return (
    <group>
      <mesh position={[0, 10, -100]}><boxGeometry args={[200, 20, 2]} /><meshStandardMaterial color="#111" /></mesh>
      <mesh position={[0, 10, 100]}><boxGeometry args={[200, 20, 2]} /><meshStandardMaterial color="#111" /></mesh>
      <mesh position={[-100, 10, 0]} rotation={[0, Math.PI / 2, 0]}><boxGeometry args={[200, 20, 2]} /><meshStandardMaterial color="#111" /></mesh>
      <mesh position={[100, 10, 0]} rotation={[0, Math.PI / 2, 0]}><boxGeometry args={[200, 20, 2]} /><meshStandardMaterial color="#111" /></mesh>
      {[[-20, -20], [20, -20], [-20, 20], [20, 20]].map(([x, z], i) => (
        <group key={i} position={[x, 10, z]}>
          <mesh><boxGeometry args={[5, 20, 5]} /><meshStandardMaterial color="#151515" /></mesh>
          <mesh position={[0, 0, 2.6]}><boxGeometry args={[2, 18, 0.2]} /><meshStandardMaterial color="#00ffff" emissive="#00ffff" emissiveIntensity={2} /></mesh>
        </group>
      ))}
      {[[-10, 0], [10, 0], [0, -15], [0, 15], [30, 30], [-30, -30]].map(([x, z], i) => (
        <mesh key={i} position={[x, 1, z]}><boxGeometry args={[8, 2, 2]} /><meshStandardMaterial color="#222" /></mesh>
      ))}
      {extractionReady && (
        <group position={[0, 0.1, 0]}>
          <mesh rotation={[-Math.PI / 2, 0, 0]}><ringGeometry args={[4, 5, 32]} /><meshStandardMaterial color="#10b981" emissive="#10b981" emissiveIntensity={5} transparent opacity={0.5} /></mesh>
          <pointLight color="#10b981" intensity={10} distance={15} />
        </group>
      )}
    </group>
  );
};

const PlayerController: React.FC<{ extractionReady: boolean; onVictory: () => void }> = ({ extractionReady, onVictory }) => {
  const { camera } = useThree();
  const keys = useKeyboard();
  const verticalVelocity = useRef(0);
  const isGrounded = useRef(true);
  const GROUND_Y = 1.8;

  useFrame((_, delta) => {
    const moveSpeed = keys.shift ? 14 : 8;
    const direction = new THREE.Vector3(Number(keys.right) - Number(keys.left), 0, Number(keys.backward) - Number(keys.forward)).normalize();
    if (direction.length() > 0) {
        const forward = new THREE.Vector3(0, 0, -1).applyQuaternion(camera.quaternion).setY(0).normalize();
        const right = new THREE.Vector3(1, 0, 0).applyQuaternion(camera.quaternion).setY(0).normalize();
        camera.position.add(forward.multiplyScalar(-direction.z * moveSpeed * delta));
        camera.position.add(right.multiplyScalar(direction.x * moveSpeed * delta));
    }
    if (keys.jump && isGrounded.current) {
      verticalVelocity.current = 12;
      isGrounded.current = false;
    }
    if (!isGrounded.current) {
      verticalVelocity.current -= 30 * delta;
      camera.position.y += verticalVelocity.current * delta;
      if (camera.position.y <= GROUND_Y) {
        camera.position.y = GROUND_Y;
        verticalVelocity.current = 0;
        isGrounded.current = true;
      }
    }
    camera.position.x = THREE.MathUtils.clamp(camera.position.x, -95, 95);
    camera.position.z = THREE.MathUtils.clamp(camera.position.z, -95, 95);
    if (extractionReady && new THREE.Vector2(camera.position.x, camera.position.z).length() < 5) onVictory();
  });
  return null;
};

const EnemyNPC: React.FC<{ enemy: Enemy; onHit: (id: string, pos: THREE.Vector3) => void; onPlayerHurt: () => void }> = ({ enemy, onHit, onPlayerHurt }) => {
  const groupRef = useRef<THREE.Group>(null);
  const bodyRef = useRef<THREE.Group>(null);
  const { camera } = useThree();
  const lastFireTime = useRef(0);

  useFrame((state) => {
    if (!groupRef.current || !enemy.isAlive) return;
    const t = state.clock.getElapsedTime();
    groupRef.current.lookAt(camera.position.x, enemy.position[1], camera.position.z);
    if (camera.position.distanceTo(new THREE.Vector3(...enemy.position)) < 50 && t - lastFireTime.current > (2 + Math.random() * 3)) {
      lastFireTime.current = t;
      if (Math.random() > 0.7) onPlayerHurt();
    }
  });

  if (!enemy.isAlive) return null;
  const armorColor = enemy.type === 'tank' ? '#333' : '#1a1a1a';
  const detailColor = enemy.type === 'tank' ? '#ffaa00' : '#ff3333';
  const scale = enemy.type === 'tank' ? 1.3 : 1.0;

  return (
    <group ref={groupRef} position={enemy.position} scale={[scale, scale, scale]}>
      <group ref={bodyRef} onClick={(e) => { e.stopPropagation(); onHit(enemy.id, e.point); }}>
        <mesh position={[0, 1.2, 0]}><boxGeometry args={[0.6, 0.8, 0.3]} /><meshStandardMaterial color={armorColor} metalness={0.7} roughness={0.2} /></mesh>
        <group position={[0, 1.8, 0]}>
          <mesh><boxGeometry args={[0.3, 0.35, 0.3]} /><meshStandardMaterial color="#0a0a0a" /></mesh>
          <mesh position={[0, 0, 0.16]}><boxGeometry args={[0.25, 0.05, 0.02]} /><meshStandardMaterial color={detailColor} emissive={detailColor} emissiveIntensity={4} /></mesh>
        </group>
        <mesh position={[-0.45, 1.4, 0]}><boxGeometry args={[0.2, 0.6, 0.2]} /><meshStandardMaterial color={armorColor} /></mesh>
        <mesh position={[0.45, 1.4, 0]}><boxGeometry args={[0.2, 0.6, 0.2]} /><meshStandardMaterial color={armorColor} /></mesh>
        <mesh position={[-0.2, 0.4, 0]}><boxGeometry args={[0.22, 0.8, 0.22]} /><meshStandardMaterial color="#111" /></mesh>
        <mesh position={[0.2, 0.4, 0]}><boxGeometry args={[0.22, 0.8, 0.22]} /><meshStandardMaterial color="#111" /></mesh>
      </group>
      <pointLight position={[0, 1.5, 0]} intensity={0.5} color={detailColor} distance={5} />
    </group>
  );
};

const Scene: React.FC<GameWorldProps> = ({ isPaused, onHit, onKill, onFire, onVictory, enemiesRemaining, currentWeaponType }) => {
  const vfxRef = useRef<any>(null);
  const { camera, scene } = useThree();
  const [isFiring, setIsFiring] = useState(false);
  const [enemies, setEnemies] = useState<Enemy[]>([]);
  const lastShootTime = useRef(0);
  const mousePressed = useRef(false);

  useEffect(() => {
    const list: Enemy[] = [];
    for (let i = 0; i < 18; i++) {
        const angle = (i / 18) * Math.PI * 2;
        const radius = 30 + Math.random() * 50;
        list.push({ id: `e-${i}`, position: [Math.cos(angle) * radius, 0, Math.sin(angle) * radius], health: 100, type: i % 5 === 0 ? 'tank' : 'soldier', isAlive: true });
    }
    setEnemies(list);
  }, []);

  const handleShoot = useCallback(() => {
    const config = WEAPONS[currentWeaponType];
    const now = performance.now();
    if (now - lastShootTime.current < config.fireRate) return;

    lastShootTime.current = now;
    onFire();
    setIsFiring(true);
    setTimeout(() => setIsFiring(false), 50);

    const raycaster = new THREE.Raycaster();

    // Shoot multiple projectiles for shotgun
    for (let i = 0; i < config.projectiles; i++) {
        const spreadOffset = new THREE.Vector2(
            (Math.random() - 0.5) * config.spread,
            (Math.random() - 0.5) * config.spread
        );
        raycaster.setFromCamera(spreadOffset, camera);
        const intersects = raycaster.intersectObjects(scene.children, true);

        if (intersects.length > 0) {
            const hit = intersects[0];
            // Check if we hit an enemy (via the parent group/ref logic)
            let current = hit.object;
            let enemyId = null;
            while (current && !enemyId) {
                if ((current as any).userData?.enemyId) {
                    enemyId = (current as any).userData.enemyId;
                }
                current = current.parent as any;
            }

            if (vfxRef.current) {
                const hitColor = hit.object.type === 'Mesh' ? new THREE.Color(0x00ffff) : new THREE.Color(0xffaa00);
                vfxRef.current.triggerEffect(hit.point, hitColor, 15, 0.15);
            }
        }
    }
  }, [camera, scene, onFire, currentWeaponType]);

  useFrame(() => {
    if (mousePressed.current && !isPaused && WEAPONS[currentWeaponType].automatic) {
      handleShoot();
    }
  });

  useEffect(() => {
    const handleMouseDown = (e: MouseEvent) => { 
        if (e.button === 0 && !isPaused) {
            mousePressed.current = true;
            if (!WEAPONS[currentWeaponType].automatic) handleShoot();
        }
    };
    const handleMouseUp = (e: MouseEvent) => { if (e.button === 0) mousePressed.current = false; };
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
        window.removeEventListener('mousedown', handleMouseDown);
        window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [handleShoot, isPaused, currentWeaponType]);

  const handleEnemyHit = (id: string, pos: THREE.Vector3) => {
    setEnemies(prev => prev.map(e => {
        if (e.id === id) {
            onKill();
            if (vfxRef.current) vfxRef.current.triggerEffect(pos, new THREE.Color(0xff0000), 40, 0.4);
            return { ...e, isAlive: false };
        }
        return e;
    }));
  };

  return (
    <>
      <Sky sunPosition={[100, 20, 100]} />
      <Stars radius={150} depth={50} count={7000} factor={4} />
      <ambientLight intensity={0.1} />
      <pointLight position={[0, 15, 0]} intensity={2} color="#00ffff" />
      <Environment preset="city" />
      <mesh rotation={[-Math.PI / 2, 0, 0]} receiveShadow>
        <planeGeometry args={[1000, 1000]} />
        <meshStandardMaterial color="#050505" metalness={0.9} roughness={0.3} />
      </mesh>
      <TacticalMap extractionReady={enemiesRemaining <= 0} />
      <VFXManager ref={vfxRef} />
      {enemies.map(enemy => (
        <group key={enemy.id} userData={{ enemyId: enemy.id }}>
           <EnemyNPC enemy={enemy} onHit={handleEnemyHit} onPlayerHurt={onHit} />
        </group>
      ))}
      {!isPaused && (
        <group>
          <PlayerController extractionReady={enemiesRemaining <= 0} onVictory={onVictory} />
          <Weapon isFiring={isFiring} type={currentWeaponType} />
          <PointerLockControls />
        </group>
      )}
    </>
  );
};

const GameWorld: React.FC<GameWorldProps> = (props) => {
  return (
    <div className="w-full h-full cursor-crosshair">
      <Canvas shadows camera={{ fov: 75, position: [0, 1.8, 10] }}>
        <Scene {...props} />
      </Canvas>
    </div>
  );
};

export default GameWorld;

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { WeaponType } from '../types';

interface WeaponProps {
  isFiring: boolean;
  type: WeaponType;
}

const Weapon: React.FC<WeaponProps> = ({ isFiring, type }) => {
  const groupRef = useRef<THREE.Group>(null);
  const muzzleFlashRef = useRef<THREE.Group>(null);
  const shellRef = useRef<THREE.Mesh>(null);
  const armRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (!groupRef.current) return;

    const time = state.clock.getElapsedTime();

    // Weapon and Arm sway
    const swayX = Math.sin(time * 1.5) * 0.008;
    const swayY = Math.cos(time * 2) * 0.008;

    // Base position (Bottom Right)
    groupRef.current.position.set(0.55 + swayX, -0.45 + swayY, -0.8);

    // Recoil and Muzzle Flash intensity based on type
    const recoilIntensity = type === WeaponType.SHOTGUN ? 0.25 : type === WeaponType.RIFLE ? 0.06 : 0.1;
    const recoilRot = type === WeaponType.SHOTGUN ? 0.2 : 0.08;

    if (isFiring) {
        groupRef.current.position.z += recoilIntensity;
        groupRef.current.rotation.x += recoilRot;
        if (muzzleFlashRef.current) {
            muzzleFlashRef.current.visible = true;
            const flashScale = type === WeaponType.SHOTGUN ? 2.5 : 1.2;
            muzzleFlashRef.current.scale.setScalar(flashScale + Math.random() * 0.5);
            muzzleFlashRef.current.rotation.z = Math.random() * Math.PI;
        }
    } else {
        groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, 0, 0.2);
        groupRef.current.position.z = THREE.MathUtils.lerp(groupRef.current.position.z, -0.8, 0.2);
        if (muzzleFlashRef.current) muzzleFlashRef.current.visible = false;
    }

    // Shell ejection logic
    if (shellRef.current && isFiring) {
        shellRef.current.visible = true;
        shellRef.current.position.set(0.1, 0.05, -0.2);
    }
    if (shellRef.current && shellRef.current.visible) {
        shellRef.current.position.x += 0.12;
        shellRef.current.position.y += 0.08;
        shellRef.current.rotation.x += 0.8;
        if (shellRef.current.position.x > 1.2) shellRef.current.visible = false;
    }
  });

  return (
    <group ref={groupRef}>
      {/* PLAYER ARM & HAND */}
      <group position={[-0.1, -0.2, 0.4]}>
        {/* Forearm */}
        <mesh rotation={[Math.PI / 10, 0, 0]}>
          <boxGeometry args={[0.2, 0.2, 0.8]} />
          <meshStandardMaterial color="#0a0a0a" roughness={0.8} />
        </mesh>
        {/* Tactical Glove / Hand */}
        <mesh position={[0, 0.1, -0.4]}>
          <boxGeometry args={[0.18, 0.18, 0.22]} />
          <meshStandardMaterial color="#111" metalness={0.2} />
        </mesh>
        {/* Thumb Grip Detail */}
        <mesh position={[0.08, 0.15, -0.45]}>
          <boxGeometry args={[0.04, 0.1, 0.1]} />
          <meshStandardMaterial color="#1a1a1a" />
        </mesh>
      </group>

      {/* WEAPON MODEL */}
      <group position={[0, 0, 0]}>
        {/* Grip */}
        <mesh position={[0, -0.15, 0.1]} rotation={[Math.PI / 8, 0, 0]}>
          <boxGeometry args={[0.12, 0.4, 0.15]} />
          <meshStandardMaterial color="#222" />
        </mesh>

        {/* Receiver / Main Body */}
        <mesh position={[0, 0.05, -0.1]}>
          <boxGeometry args={[
            type === WeaponType.SHOTGUN ? 0.22 : type === WeaponType.RIFLE ? 0.18 : 0.14,
            0.22,
            type === WeaponType.PISTOL ? 0.5 : 0.9
          ]} />
          <meshStandardMaterial color="#1a1a1a" metalness={0.8} roughness={0.2} />
        </mesh>

        {/* Weapon Details based on Type */}
        {type === WeaponType.RIFLE && (
          <group>
            {/* Extended Barrel */}
            <mesh position={[0, 0.05, -0.9]} rotation={[Math.PI / 2, 0, 0]}>
              <cylinderGeometry args={[0.04, 0.04, 0.8]} />
              <meshStandardMaterial color="#050505" metalness={1} />
            </mesh>
            {/* Holographic Sight Frame */}
            <mesh position={[0, 0.22, -0.1]}>
              <boxGeometry args={[0.1, 0.12, 0.15]} />
              <meshStandardMaterial color="#111" />
            </mesh>
            {/* Holographic Reticle Glow */}
            <mesh position={[0, 0.24, -0.1]}>
              <planeGeometry args={[0.06, 0.06]} />
              <meshBasicMaterial color="#00ffff" transparent opacity={0.6} />
            </mesh>
            {/* Magazine */}
            <mesh position={[0, -0.3, -0.2]} rotation={[Math.PI / 10, 0, 0]}>
              <boxGeometry args={[0.12, 0.4, 0.2]} />
              <meshStandardMaterial color="#111" />
            </mesh>
          </group>
        )}

        {type === WeaponType.SHOTGUN && (
          <group>
            {/* Heavy Twin Barrels */}
            <mesh position={[-0.05, 0.05, -0.8]} rotation={[Math.PI / 2, 0, 0]}>
              <cylinderGeometry args={[0.05, 0.05, 0.7]} />
              <meshStandardMaterial color="#050505" metalness={1} />
            </mesh>
            <mesh position={[0.05, 0.05, -0.8]} rotation={[Math.PI / 2, 0, 0]}>
              <cylinderGeometry args={[0.05, 0.05, 0.7]} />
              <meshStandardMaterial color="#050505" metalness={1} />
            </mesh>
            {/* Pump Handle / Heat Shield */}
            <mesh position={[0, -0.05, -0.5]}>
              <boxGeometry args={[0.24, 0.1, 0.6]} />
              <meshStandardMaterial color="#222" />
            </mesh>
          </group>
        )}

        {type === WeaponType.PISTOL && (
          <group>
            {/* Slide Top */}
            <mesh position={[0, 0.16, -0.1]}>
              <boxGeometry args={[0.12, 0.05, 0.52]} />
              <meshStandardMaterial color="#2a2a2a" metalness={0.9} />
            </mesh>
            {/* Laser Sight Under-barrel */}
            <mesh position={[0, -0.08, -0.3]}>
              <boxGeometry args={[0.06, 0.06, 0.2]} />
              <meshStandardMaterial color="#111" />
            </mesh>
            <mesh position={[0, -0.08, -0.4]} rotation={[Math.PI / 2, 0, 0]}>
              <cylinderGeometry args={[0.01, 0.01, 0.01]} />
              <meshBasicMaterial color="#ff0000" />
            </mesh>
          </group>
        )}

        {/* Global Battery / Magazine Glow (Common Futuristic Detail) */}
        <mesh position={[0, -0.05, 0.1]}>
          <boxGeometry args={[0.16, 0.08, 0.1]} />
          <meshStandardMaterial color="#00ffff" emissive="#00ffff" emissiveIntensity={2} />
        </mesh>
      </group>

      {/* Shell Ejection Port */}
      <mesh ref={shellRef} visible={false}>
        <cylinderGeometry args={[0.012, 0.012, 0.05]} />
        <meshStandardMaterial color="#d4af37" metalness={1} />
      </mesh>

      {/* Volumetric Muzzle Flash */}
      <group ref={muzzleFlashRef} position={[0, 0.05, type === WeaponType.RIFLE ? -1.3 : type === WeaponType.SHOTGUN ? -1.1 : -0.6]} visible={false}>
        <mesh>
            <sphereGeometry args={[0.15, 8, 8]} />
            <meshBasicMaterial color="#00ffff" transparent opacity={0.8} />
        </mesh>
        <mesh rotation={[0, 0, Math.PI / 4]}>
            <boxGeometry args={[0.5, 0.03, 0.03]} />
            <meshBasicMaterial color="#ffffff" />
        </mesh>
        <mesh rotation={[0, 0, -Math.PI / 4]}>
            <boxGeometry args={[0.5, 0.03, 0.03]} />
            <meshBasicMaterial color="#ffffff" />
        </mesh>
        <pointLight intensity={15} color="#00ffff" distance={8} />
      </group>
    </group>
  );
};

export default Weapon;

export enum GameState {
  MENU = 'MENU',
  LOADING = 'LOADING',
  PLAYING = 'PLAYING',
  GAMEOVER = 'GAMEOVER',
  MISSION_BRIEF = 'MISSION_BRIEF',
  VICTORY = 'VICTORY'
}

export enum WeaponType {
  PISTOL = 'PISTOL',
  RIFLE = 'RIFLE',
  SHOTGUN = 'SHOTGUN'
}

export interface WeaponConfig {
  name: string;
  type: WeaponType;
  fireRate: number; // ms between shots
  ammoCapacity: number;
  damage: number;
  spread: number;
  projectiles: number;
  automatic: boolean;
}

