    type: WeaponType.PISTOL,
    fireRate: 250,
    ammoCapacity: 15,
    damage: 25,
    spread: 0.01,
    projectiles: 1,
    automatic: false
  },
  [WeaponType.RIFLE]: {
    name: 'V-40 ASSAULT DISRUPTOR',
    type: WeaponType.RIFLE,
    fireRate: 100,
    ammoCapacity: 35,
    damage: 15,
    spread: 0.04,
    projectiles: 1,
    automatic: true
  },
  [WeaponType.SHOTGUN]: {
    name: 'S-12 PULSE BREACHER',
    type: WeaponType.SHOTGUN,
    fireRate: 800,
    ammoCapacity: 8,
    damage: 12, // per projectile
    spread: 0.15,
